from openai_agents import Runner
from collections import Counter

def detect_handoff_loops(runner: Runner) -> dict:
    traces = runner.get_traces()
    handoffs = []

    for trace in traces:
        if hasattr(trace, 'handoff_to'):
            handoffs.append(trace.agent_id + '->' + trace.handoff_to)

    loop_patterns = Counter(handoffs)
    loops = {k: v for k, v in loop_patterns.items() if v > 3}

    if loops:
        print(f'🔄 Loop detected: {loops}')
        return {'loops_detected': len(loops), 'patterns': loops}
    return {'loops_detected': 0}

